string[] stages = { "投料", "烘干", "传送", "质检", "包装" };
int[] addrs = { 100, 200, 300, 400, 500 };
int ok = 0, alarm = 0;
for (int i = 0; i < 5; i++) {
    ushort t = Plc.ReadHoldingRegister(addrs[i]);
    if (t < 300) { ok++; Print($"{stages[i]}: {t/10.0}°C 正常"); }
    else { alarm++; Print($"{stages[i]}: {t/10.0}°C 异常"); }
}
Print($"正常{ok}段, 异常{alarm}段, 运行率{ok*100.0/5:F0}%");
Print("===== 产线联调完成 =====");
